VALUES
  ('aboriginal-0a2fc18c-moex-00013', 'aboriginal-0a2fc18c', 'aboriginal-0a2fc18c-moex-114-d3ff7f6b', 'sub-aboriginal-0a2fc18c-03', NULL, 'single_choice', '假設A商品市場的供需法則均成立，且A 商品的市場均衡價格為8元。若政府決定設定價格上 限（priceceiling）為10元，則此政策會造成消費者剩餘及生產者剩餘如何變化？', '["消費者剩餘不改變，且生產者剩餘也不改變", "消費者剩餘不改變，但生產者剩餘增加", "消費者剩餘減少，但生產者剩餘的變化不確定", "消費者剩餘的變化不確定，但生產者剩餘會減少"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:40+00:00", "source_pdf_sha1": "9aa9fc32b976", "answer_pdf_sha1": "b963ad1973f0", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "509", "s": "1109", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "經建行政"}'::jsonb, NULL),
  ('aboriginal-0a2fc18c-moex-00014', 'aboriginal-0a2fc18c', 'aboriginal-0a2fc18c-moex-114-d3ff7f6b', 'sub-aboriginal-0a2fc18c-03', NULL, 'single_choice', '某人對咖啡（X）與茶（Y）的效用函數為U=2X+Y，而咖啡與茶的價格皆為50。若此人的所得 為1,000，則其最適選擇為何？', '["X=5，Y=15", "X=10，Y=10", "X=20，Y=0", "X=0，Y=20"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:40+00:00", "source_pdf_sha1": "9aa9fc32b976", "answer_pdf_sha1": "b963ad1973f0", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "509", "s": "1109", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "經建行政"}'::jsonb, NULL),
  ('aboriginal-0a2fc18c-moex-00015', 'aboriginal-0a2fc18c', 'aboriginal-0a2fc18c-moex-114-d3ff7f6b', 'sub-aboriginal-0a2fc18c-03', NULL, 'single_choice', '當產量增加時，若平均總成本增加，則下列敘述何者正確？', '["平均總成本增加的幅度大於平均變動成本增加的幅度", "平均總成本增加的幅度小於平均變動成本增加的幅度", "平均總成本增加的幅度等於平均變動成本增加的幅度", "平均變動成本增加的幅度大於平均固定成本增加的幅度"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:40+00:00", "source_pdf_sha1": "9aa9fc32b976", "answer_pdf_sha1": "b963ad1973f0", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "509", "s": "1109", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "經建行政"}'::jsonb, NULL),
  ('aboriginal-0a2fc18c-moex-00016', 'aboriginal-0a2fc18c', 'aboriginal-0a2fc18c-moex-114-d3ff7f6b', 'sub-aboriginal-0a2fc18c-03', NULL, 'single_choice', '若某產品的需求函數為Q=100-2P，其中P為價格，Q為需求量，且其邊際成本固定在MC=40， 如果只有一家廠商生產該產品，使其利潤極大的最適產量水準為何？', '["10", "15", "20", "25"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:40+00:00", "source_pdf_sha1": "9aa9fc32b976", "answer_pdf_sha1": "b963ad1973f0", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "509", "s": "1109", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "經建行政"}'::jsonb, NULL),
  ('aboriginal-0a2fc18c-moex-00017', 'aboriginal-0a2fc18c', 'aboriginal-0a2fc18c-moex-114-d3ff7f6b', 'sub-aboriginal-0a2fc18c-03', NULL, 'single_choice', '假設A公司為獨占廠商，其生產一種產品，成本函數C(Q)=30Q，賣到兩個國家，甲國的需求彈 性為2，乙國的需求彈性為3，若該公司採取差別定價以追求利潤極大，在兩國的定價應為何？', '["甲國定價30，乙國定價30", "甲國定價60，乙國定價45", "甲國定價60，乙國定價30", "甲國定價30，乙國定價45 1"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:40+00:00", "source_pdf_sha1": "9aa9fc32b976", "answer_pdf_sha1": "b963ad1973f0", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "509", "s": "1109", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "經建行政"}'::jsonb, NULL),
  ('aboriginal-0a2fc18c-moex-00018', 'aboriginal-0a2fc18c', 'aboriginal-0a2fc18c-moex-114-d3ff7f6b', 'sub-aboriginal-0a2fc18c-03', NULL, 'single_choice', '假設在一獨占性競爭市場裡每一家廠商所面對的需求函數可表述如下：q S[ b(p P)]， i N i i1,...,N，其中p 與q 表示為產品i的市場價格與需求量，P為產業裡所有產品的平均價格，S為 i i 市場規模，N為廠商數目，b為一常數值。關於此一需求函數，下列敘述何者正確？', '["單一產品的價格若與產業平均價格差距愈大，則該產品的需求量愈小", "單一產品的價格若與產業平均價格差距愈小，則該產品的需求量愈小", "常數b為一負值", "常數b為一正值"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:40+00:00", "source_pdf_sha1": "9aa9fc32b976", "answer_pdf_sha1": "b963ad1973f0", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "509", "s": "1109", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "經建行政"}'::jsonb, NULL),
  ('aboriginal-0a2fc18c-moex-00019', 'aboriginal-0a2fc18c', 'aboriginal-0a2fc18c-moex-114-d3ff7f6b', 'sub-aboriginal-0a2fc18c-03', NULL, 'single_choice', '假設甲國的勞動邊際產量（marginalproductoflabor）為100-0.2N（其中N為勞動需求量）而勞動 供給為 10+w（其中 w 為實質工資率），如果政府實施最低工資為 w = 90，則甲國非自願性失業 （involuntaryunemployment）為何？', '["0", "10", "50", "100"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:40+00:00", "source_pdf_sha1": "9aa9fc32b976", "answer_pdf_sha1": "b963ad1973f0", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "509", "s": "1109", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "經建行政"}'::jsonb, NULL),
  ('aboriginal-0a2fc18c-moex-00020', 'aboriginal-0a2fc18c', 'aboriginal-0a2fc18c-moex-114-d3ff7f6b', 'sub-aboriginal-0a2fc18c-03', NULL, 'single_choice', '小丁進入一家麵包店求職，他向追求利潤最大的老闆保證，在他被僱用後，每天可以為此麵包店 多賣5塊麵包，且每塊麵包會以60元售出。如果小丁所言不假，但是老闆並未僱用他，下列敘述 何者正確？', '["此麵包店付給每位員工的日薪小於300元", "僱用小丁後，此麵包店的勞工邊際產量會變為負值", "僱用小丁前，此麵包店付給每位員工的日薪小於60元", "僱用小丁前，此麵包店付給每位員工的日薪大於300元"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:40+00:00", "source_pdf_sha1": "9aa9fc32b976", "answer_pdf_sha1": "b963ad1973f0", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "509", "s": "1109", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "經建行政"}'::jsonb, NULL),
  ('aboriginal-0a2fc18c-moex-00021', 'aboriginal-0a2fc18c', 'aboriginal-0a2fc18c-moex-114-d3ff7f6b', 'sub-aboriginal-0a2fc18c-03', NULL, 'single_choice', '張三的效用函數為U(I)=I2，其中I>0為所得，他有兩個工作機會，其中一個工作固定薪水10萬 元，另一個是業務工作，有p的機率得薪水12萬元，（1-p）的機率得薪水8萬元，下列敘述何者 錯誤？', '["張三為風險愛好者", "張三的貨幣邊際效用遞增", "當p=0.5時，因業務工作的期望報酬等於固定薪水，張三會選擇固定薪水的工作", "當p≧0.45時，張三會選擇業務工作"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:40+00:00", "source_pdf_sha1": "9aa9fc32b976", "answer_pdf_sha1": "b963ad1973f0", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "509", "s": "1109", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "經建行政"}'::jsonb, NULL),
  ('aboriginal-0a2fc18c-moex-00022', 'aboriginal-0a2fc18c', 'aboriginal-0a2fc18c-moex-114-d3ff7f6b', 'sub-aboriginal-0a2fc18c-03', NULL, 'single_choice', '假設某產品的市場需求為Qd=200-P，市場供給為Qs=P，其中Q為產品數量，P為產品價格。 此產品生產過程會排放污染，每單位產量所排放污染之社會成本為 20 元，若政府決定對每單位 產量課徵20元的稅，則社會總剩餘變化為何？', '["社會總剩餘在課稅前為10,000元，課稅後為9,900元，降低100元", "社會總剩餘在課稅前為10,000元，課稅後為12,000元，增加2,000元", "社會總剩餘在課稅前為8,000元，課稅後為8,100元，增加100元", "社會總剩餘在課稅前為8,000元，課稅後為7,900元，降低100元"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:40+00:00", "source_pdf_sha1": "9aa9fc32b976", "answer_pdf_sha1": "b963ad1973f0", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "509", "s": "1109", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "經建行政"}'::jsonb, NULL)
